import { defineField, defineType } from 'sanity'

export const galleryType = defineType({
  name: 'gallery',
  title: 'Galeri & Medya Koleksiyonu',
  type: 'document',
  fields: [
    defineField({
      name: 'title',
      title: 'Koleksiyon Adı',
      description: 'Örn: 2024 Tarım Tesisleri İncelenmesi',
      type: 'string',
      validation: (Rule) => Rule.required(),
    }),
    defineField({
      name: 'category',
      title: 'Kategori',
      type: 'string',
      options: {
        list: [
          { title: 'Tarım Tesisleri', value: 'tarim' },
          { title: 'Lojistik Filo', value: 'lojistik' },
          { title: 'Kurumsal Ofisler', value: 'kurumsal' },
          { title: 'Sanayi/Üretim', value: 'sanayi' },
        ],
      },
      validation: (Rule) => Rule.required(),
    }),
    defineField({
      name: 'coverImage',
      title: 'Kapak Görseli',
      description: 'Kartlarda ve listelerde görünecek ana resim',
      type: 'image',
      options: { hotspot: true },
      validation: (Rule) => Rule.required(),
    }),
    defineField({
      name: 'images',
      title: 'Koleksiyon Görselleri',
      description: 'Bu koleksiyona ait birden fazla resim ekleyebilirsiniz',
      type: 'array',
      of: [{ type: 'image', options: { hotspot: true } }],
    }),
    defineField({
      name: 'videoUrl',
      title: 'Video Linki (Opsiyonel)',
      description: 'Varsa YouTube veya MP4 linki',
      type: 'url',
    }),
  ],
  preview: {
    select: {
      title: 'title',
      subtitle: 'category',
      media: 'coverImage',
    },
  },
})
